+        detectedHeader = `${headerMatch[1].trim()}:`;
+        const remainder = headerMatch[2]?.trim() ?? '';
+        if (remainder.length > 0) {
+          lines[firstIndex] = remainder;
+        } else {
+          lines.splice(firstIndex, 1);
+        }
+      }
+    }
+
+    return {
+      lines,
+      header: detectedHeader,
+    };
+  }, [snapshot.git.summary]);
